begin;

-- 1. Insert RMP Programme
values (
  '10000000-0000-4000-8000-000000000069',
  'RMP',
  'Risk Management Professional',
  'Evaluates proficiency in risk planning, qualitative and quantitative risk analysis, risk response strategies, contingency planning, and enterprise risk management (ERM).',
  true
)
on conflict (code) do update
set name = excluded.name,
    description = excluded.description,
    is_active = true,
    updated_at = now();

-- 2. Insert RMP Examination
  id, programme_id, title, instructions, duration_minutes, pass_mark,
  status, max_attempts, randomize_questions, randomize_options,
  allow_self_enrollment
)
values (
  '20000000-0000-4000-8000-000000000069',
  '10000000-0000-4000-8000-000000000069',
  'Risk Management Professional (RMP)',
  'Answer all 75 multiple-choice questions. This advanced-level examination evaluates risk identification, risk evaluation, and resilient project response configurations.',
  120,
  70,
  'published',
  1,
  false,
  false,
  true
)
on conflict (id) do update
set programme_id = excluded.programme_id,
    title = excluded.title,
    instructions = excluded.instructions,
    duration_minutes = excluded.duration_minutes,
    pass_mark = excluded.pass_mark,
    status = excluded.status,
    max_attempts = excluded.max_attempts,
    randomize_questions = excluded.randomize_questions,
    randomize_options = excluded.randomize_options,
    allow_self_enrollment = excluded.allow_self_enrollment,
    updated_at = now();

-- 3. Insert Questions (75 questions)
on conflict (id) do update
set question_text = excluded.question_text,
    position = excluded.position,
    updated_at = now();

-- 4. Insert Options (300 options)
on conflict (id) do update
set option_text = excluded.option_text,
    position = excluded.position;

-- 5. Insert Question Answer Keys (75 keys)
on conflict (question_id) do update
set correct_option_id = excluded.correct_option_id,
    explanation = excluded.explanation,
    updated_at = now();

